import{_ as t,o as n,c as a,a3 as o}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"14A. Independent Dispute Resolution Panel","description":"","frontmatter":{"title":"14A. Independent Dispute Resolution Panel","eba":"Allied Health Professionals 2021-2026","topics":["disputes","union-matters","staffing","workload"]},"headers":[],"relativePath":"ebas/allied-health/consultation-disputes/14A-independent-dispute-resolution-panel.md","filePath":"ebas/allied-health/consultation-disputes/14A-independent-dispute-resolution-panel.md"}'),i={name:"ebas/allied-health/consultation-disputes/14A-independent-dispute-resolution-panel.md"};function s(r,e,l,p,d,h){return n(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="_14a-independent-dispute-resolution-panel" tabindex="-1">14A. Independent Dispute Resolution Panel <a class="header-anchor" href="#_14a-independent-dispute-resolution-panel" aria-label="Permalink to &quot;14A. Independent Dispute Resolution Panel&quot;">​</a></h1><p><strong>14A.1</strong> Application The Independent Dispute Resolution Panel (Panel) is empowered to hear and determine dispute applications regarding the following matters:</p><p><strong>(a)</strong> <a href="/eba/ebas/allied-health/classification-staffing/89-supervision-and-management.html">clause 89</a> – Supervision and Management;</p><p><strong>(b)</strong> <a href="/eba/ebas/allied-health/classification-staffing/90-workload-allocation-and-safe-staffing.html">clause 90</a> –Workload Allocation and Safe Staffing;</p><p><strong>(c)</strong> <a href="/eba/ebas/allied-health/classification-staffing/91-backfill.html">clause 91</a> – Backfill; and</p><p><strong>(d)</strong> the classification of an Employee/s under this Agreement (including in relation to Advanced Practice).</p><p><strong>14A.2</strong> Composition and principles of the Panel</p><p><strong>(a)</strong> The Panel for a dispute will comprise three (3) persons being:</p><p><strong>(i)</strong> a nominee of the Union (on behalf of Employees);</p><p><strong>(ii)</strong> a nominee of the VHIA (on behalf of Employers); and</p><p><strong>(iii)</strong> an independent chairperson (Chair) agreed by the Union and the VHIA or, where agreement cannot be reached in a reasonable timeframe, as nominated by the Minister for Health.</p><p><strong>(b)</strong> The Panel Chair shall act as an independent third party in deliberations of the Panel.</p><p><strong>(c)</strong> A nominee on the Panel must recuse themselves from being involved in a matter if they are directly and/or personally affected by the outcome.</p><p><strong>(d)</strong> The Panel will commence determining an application made under this clause 14A within 21 days of receiving the application and conclude its deliberations as expeditiously as possible.</p><p><strong>(e)</strong> The Panel shall act independently of the Union, the VHIA and the Victorian Government.</p><p><strong>(f)</strong> The parties to an application to the Panel bear their own costs (save for the Chair).</p><p><strong>(g)</strong> The Panel shall be responsible for determining its own procedure, provided that it applies the rules of natural justice and procedural fairness and be consistent with the requirements of <a href="/eba/ebas/allied-health/consultation-disputes/14-dispute-resolution-procedure.html">clause 14</a> Dispute Resolution Procedure.</p><p><strong>(h)</strong> The Panel shall apply an inquisitorial procedure, rather than an adversarial one.</p><p><strong>(i)</strong> The Panel may decide to hear a matter in the workplace. In such cases the Employer shall provide a suitable meeting room and other relevant facilities for any date requested by the Panel. The Employer will allow the Panel to inspect any work site if the Panel believes this will assist it in determining a matter, subject to any health, safety and privacy considerations. A party to a dispute may request that the Panel hear a matter in a workplace. The Panel will consider such a request and determine for itself the best location for hearing a matter.</p><p><strong>(j)</strong> Lawyers and paid agents, who are not direct employees of the Unions, VHIA, Department or an Employer may only appear before the Panel where it gives them permission to do so.</p><p><strong>(k)</strong> Nothing in this clause 14A prevents an application to the Commission to deal with a matter that has been dealt with by the Panel.</p><p><strong>14A.3</strong> Functions of the Panel Chair</p><p><strong>(a)</strong> The Chair shall perform the following functions:</p><p><strong>(i)</strong> notify all parties to the matter and the Department of the hearing dates;</p><p><strong>(ii)</strong> chair proceedings of the Panel;</p><p><strong>(iii)</strong> conciliate matters, by chairing conferences between the Employer(s) and/or their representative/s, and the Union; and</p><p><strong>(iv)</strong> anything else necessary to give effect to the provisions of this clause 14A.</p><p><strong>14A.4</strong> Application to Panel to deal with a dispute</p><p><strong>(a)</strong> Either an Employer or an Employee/s (or their representatives) may make an application to the Panel to determine a dispute about matters listed at subclause</p><p><strong>14A.1</strong> only where the Parties have attempted to resolve the dispute at the workplace as described at subclause 14.4 of the Agreement.</p><p><strong>(b)</strong> If the provisions of subclause 14.4 (Discussion of dispute at workplace) have not been complied with prior to the application, the Chair will refer the parties back to the workplace to attempt resolution through discussion at the workplace level in the first instance.</p><p><strong>(c)</strong> Applications to the Panel to deal with a dispute will be in the following or similar form: Name of Applicant Employer Union Name of Employee/s involved Relevant Enterprise Agreement Description of the dispute and relevant issues Current status of matters</p><p>Steps already taken to resolve the dispute</p><p><strong>(d)</strong> Application by an Employee/s</p><p><strong>(i)</strong> An Employee/s may only make an application directly to the Panel where the matter directly involves and affects them.</p><p><strong>(ii)</strong> The Chair shall notify the Unions, VHIA and the Employer of an application made by an Employee/s directly to the Panel.</p><p><strong>(iii)</strong> The Union and the VHIA has a right to be heard in relation to any application made by an Employee/s directly to the Panel.</p><p><strong>(iv)</strong> Where an Employee/s makes an application directly to the Panel, any determination made by the Panel is not binding on any other Employee/s who did not make the application.</p><p><strong>14A.5</strong> Role, procedures and determinations of the Panel</p><p><strong>(a)</strong> In dealing with an application, the matters the Panel will have regard to include:</p><p><strong>(i)</strong> available relevant material;</p><p><strong>(ii)</strong> the provisions of the Agreement;</p><p><strong>(iii)</strong> materials submitted by the Employee/s and/or Unions;</p><p><strong>(iv)</strong> materials submitted by the Employer and/or VHIA;</p><p><strong>(v)</strong> in the case of submissions under subclause 14.8(d)(iii) above any materials submitted by the Union and the VHIA; and</p><p><strong>(vi)</strong> in the case of submissions under subclause 14A.6 below any materials submitted by or on behalf of the Department.</p><p><strong>(b)</strong> Subject to the provisions of this clause 14A, proceedings of the Panel shall be conducted as informally as possible and undertaken with all possible expediency.</p><p><strong>(c)</strong> The Panel may inform itself in any manner it sees fit including by seeking the views of an expert advisor (who is not an employee of the Employer subject of the application) agreed by the Panel to provide clinical expertise in an area of clinical practice relevant to the matter under consideration.</p><p><strong>(d)</strong> The Panel is not bound by the rules of evidence and procedure. The Panel will determine the manner in which an Employee/s providing evidence to the Panel will be questioned, save that where possible they will ensure that any questioning is not adversarial in nature.</p><p><strong>(e)</strong> The:</p><p><strong>(i)</strong> Employer and/or VHIA; and</p><p><strong>(ii)</strong> the Employee/s and/or Unions; can advocate to the Panel.</p><p><strong>(f)</strong> The parties to a dispute shall have full, unrestricted access to relevant information, except where the Panel determines that access to material is inappropriate for legal or confidentiality reasons.</p><p><strong>(g)</strong> An Employee/s, including a Union representative, who is involved in a matter being heard by the Panel shall be allowed time off from their normal duties and paid their normal wages for time attending.</p><p><strong>(h)</strong> The Panel will determine applications by majority, with written reasons to be prepared by the Chair (including any dissenting decision or a summary of any dissenting decision) and provided to the parties.</p><p><strong>(i)</strong> No determination of the Panel shall be regarded as a precedent.</p><p><strong>(j)</strong> A determination of the Panel will be considered binding unless the:</p><p><strong>(i)</strong> Employer and/or VHIA; and/or</p><p><strong>(ii)</strong> the Employee/s and/or Unions; makes an application to have the Commission to deal with the matter within 14 days of receiving written determination and the matter is resolved in accordance with the dispute resolution procedure.</p><p><strong>14A.6</strong> Additional Role of the Chair in considering matters affecting an Employer&#39;s funding</p><p><strong>(a)</strong> The Union and the VHIA recognise that the Victorian Government, represented by the Department, has a right to have its funding interests heard and considered in decisions of the Panel.</p><p><strong>(b)</strong> The interests of the Victorian Government represented by the Department include significant funding, policy and service delivery considerations and implications.</p><p><strong>14A.7</strong> Materials to be provided to the Panel</p><p><strong>(a)</strong> A Party shall provide all relevant material to the Panel and the other Party as soon as practicable. Relevant material may include the following:</p><p><strong>(i)</strong> staffing/EFT levels and profiles;</p><p><strong>(ii)</strong> position descriptions;</p><p><strong>(iii)</strong> rosters;</p><p><strong>(iv)</strong> proposed and/or actual professional reporting lines for/to the proposed position/s;</p><p><strong>(v)</strong> records relating to an application (for example: leave backfill, vacancies, absenteeism and leave accruals);</p><p><strong>(vi)</strong> organisational structure; and/or</p><p><strong>(vii)</strong> other material relating to supervision and management, staffing and workload and backfill.</p><p><strong>14A.8</strong> Notification of Panel determinations</p><p><strong>(a)</strong> The Chair will notify the Union, Employer and Employee/s, of the Panel&#39;s determination with respect to an application in writing within 14 days of the decision.</p><p><strong>(b)</strong> In the case of an application for a reclassification the determined Grade/Level/Class will apply from the date of the application.</p><p><strong>(c)</strong> Until the determination of the Panel, the existing Grade/Level/Class (where relevant) will continue to apply.</p><p><strong>(d)</strong> In the case of an application for a reclassification, where the Panel or, on review, the Commission determines that a lower classification applies, the Employee/s will have their current salary maintained.</p><p><strong>14A.9</strong> Employee Release from normal duty</p><p><strong>(a)</strong> An Employee/s who is involved in a dispute before the Panel, including a Union representative, will be released by the Employer with pay from normal duties as is reasonably necessary to enable them to participate in this dispute settling procedure under this clause 14A so long as it does not unduly affect the operations of the Employer.</p><p><strong>(b)</strong> For the purposes of this clause 14A &#39;pay&#39; shall include shift allowances and any other payment the Employee/s or Union representative would have received had they not been released from duty as described above.</p><p><strong>14A.10</strong> Withdrawal of application</p><p><strong>(a)</strong> The notifier of a dispute to the Panel may withdraw their application at any time.</p><p><strong>(b)</strong> Any notice of withdrawal of a matter shall be in writing and the Chair shall cause this to be communicated to other relevant parties.</p>',82)])])}const m=t(i,[["render",s]]);export{g as __pageData,m as default};
